import{_ as n,H as o,f as a,i as r}from"./chunks/framework.BHvCMIhP.js";const u=JSON.parse('{"title":"时间与空间复杂度","description":"","frontmatter":{},"headers":[],"relativePath":"../algorithmLearning/02-时间与空间复杂度.md","filePath":"../algorithmLearning/02-时间与空间复杂度.md","lastUpdated":1778496697000}'),s={name:"../algorithmLearning/02-时间与空间复杂度.md"};function e(l,t,d,i,g,p){return o(),a("div",null,[...t[0]||(t[0]=[r(`<h1 id="时间与空间复杂度" tabindex="-1">时间与空间复杂度 <a class="header-anchor" href="#时间与空间复杂度" aria-label="Permalink to &quot;时间与空间复杂度&quot;">​</a></h1><p>大 O 记号是工程师的<strong>第二母语</strong>——你跟人讨论性能,不用&quot;慢不慢&quot;,用 O(n) / O(log n) / O(n²)。但 95% 的人对大 O 的理解停留在&quot;背出常见几个&quot;,遇到稍微拐弯的场景就懵:为什么 HashMap 说&quot;平均 O(1) 最坏 O(n)&quot;?为什么动态数组的 push 是&quot;均摊 O(1)&quot;?为什么有些算法&quot;期望 O(n log n) 最坏 O(n²)&quot;?这一篇讲透。</p><blockquote><p>一句话先记住:<strong>大 O 不是公式,是一个关于&quot;数据量变大时,耗时涨得多快&quot;的粗略描述</strong>。常数、低阶项都被吃掉,只剩<strong>增长趋势</strong>。理解这一点,90% 的复杂度题都能口算。</p></blockquote><hr><h2 id="一、大-o-到底说了什么" tabindex="-1">一、大 O 到底说了什么 <a class="header-anchor" href="#一、大-o-到底说了什么" aria-label="Permalink to &quot;一、大 O 到底说了什么&quot;">​</a></h2><p>定义上,<code>f(n) = O(g(n))</code> 意思是:<strong>存在某个 n₀,从 n₀ 开始,f(n) 永远不会超过 c·g(n)</strong>(c 是某个常数)。翻译成人话:</p><ul><li>只看<strong>数据量变大时的增长率</strong></li><li>不看<strong>常数倍数</strong>(100n 和 n 都是 O(n))</li><li>不看<strong>低阶项</strong>(n² + n 就是 O(n²),n 那一项被吃掉)</li></ul><blockquote><p>为什么能忽略常数?因为<strong>常数是跟硬件、实现有关的,跟算法本身无关</strong>。一台机器跑 100n,另一台跑 10n,都是 O(n)——你换机器能解决的事,不是算法层面的问题。</p></blockquote><p><strong>直觉锚</strong>:</p><table tabindex="0"><thead><tr><th>n 增长 10 倍</th><th>耗时变化</th></tr></thead><tbody><tr><td>O(1)</td><td>不变</td></tr><tr><td>O(log n)</td><td>+1 左右(就多跑一两轮)</td></tr><tr><td>O(n)</td><td>×10</td></tr><tr><td>O(n log n)</td><td>×约 11(log n 那里多加 1)</td></tr><tr><td>O(n²)</td><td>×100</td></tr><tr><td>O(2ⁿ)</td><td>×10¹⁰⁰⁰(别玩)</td></tr></tbody></table><p><strong>工程直觉</strong>:算法面前,n = 10⁶ 是&quot;能接受&quot;的分界线:</p><ul><li>O(n) / O(n log n):10⁶ 一秒内能跑完,<strong>安全</strong></li><li>O(n²):10⁶ 平方是 10¹²,<strong>绝对跑不完</strong></li></ul><p>所以看到 n = 10⁶ 的输入,你必须<strong>O(n log n) 以内</strong>,这是硬指标。</p><hr><h2 id="二、常见复杂度对照与-从哪来" tabindex="-1">二、常见复杂度对照与&quot;从哪来&quot; <a class="header-anchor" href="#二、常见复杂度对照与-从哪来" aria-label="Permalink to &quot;二、常见复杂度对照与&quot;从哪来&quot;&quot;">​</a></h2><table tabindex="0"><thead><tr><th>复杂度</th><th>典型来源</th></tr></thead><tbody><tr><td>O(1)</td><td>哈希查、数组下标取、栈 push/pop</td></tr><tr><td>O(log n)</td><td>二分、平衡树、堆操作</td></tr><tr><td>O(n)</td><td>一次遍历、双指针</td></tr><tr><td>O(n log n)</td><td>排序、分治、每个元素做 log 次操作</td></tr><tr><td>O(n²)</td><td>双层循环、冒泡 / 选择排序</td></tr><tr><td>O(n · m)</td><td>两个数组 / 字符串交叉遍历</td></tr><tr><td>O(2ⁿ)</td><td>子集枚举、回溯</td></tr><tr><td>O(n!)</td><td>全排列</td></tr></tbody></table><p><strong>一个识别信号</strong>:看到&quot;排序后扫一遍&quot;,基本是 O(n log n);看到&quot;嵌套循环&quot;,警惕 O(n²);看到&quot;枚举子集&quot;,大概率 O(2ⁿ) 配合剪枝。</p><hr><h2 id="三、最坏-vs-平均-vs-均摊-vs-期望" tabindex="-1">三、最坏 vs 平均 vs 均摊 vs 期望 <a class="header-anchor" href="#三、最坏-vs-平均-vs-均摊-vs-期望" aria-label="Permalink to &quot;三、最坏 vs 平均 vs 均摊 vs 期望&quot;">​</a></h2><p>这四个词经常被混用,<strong>但它们说的不是一回事</strong>。</p><h3 id="最坏复杂度-worst-case" tabindex="-1">最坏复杂度(Worst Case) <a class="header-anchor" href="#最坏复杂度-worst-case" aria-label="Permalink to &quot;最坏复杂度(Worst Case)&quot;">​</a></h3><p><strong>所有输入里最慢的那次</strong>。快排最坏 O(n²)(每次都挑到最大或最小作基准)。 工程上最常用,因为<strong>生产环境上限决定了你敢不敢用</strong>。</p><h3 id="平均复杂度-average-case" tabindex="-1">平均复杂度(Average Case) <a class="header-anchor" href="#平均复杂度-average-case" aria-label="Permalink to &quot;平均复杂度(Average Case)&quot;">​</a></h3><p><strong>所有输入的数学期望</strong>。需要假设输入分布(通常假设均匀随机)。 这个值有用但也容易骗人——<strong>真实世界的输入从来不是均匀随机的</strong>。</p><h3 id="均摊复杂度-amortized" tabindex="-1">均摊复杂度(Amortized) <a class="header-anchor" href="#均摊复杂度-amortized" aria-label="Permalink to &quot;均摊复杂度(Amortized)&quot;">​</a></h3><p><strong>一系列操作的总时间,除以操作次数</strong>。单次可能很慢,但平均下来稳定。</p><p>经典例子是<strong>动态数组 push</strong>:</p><ul><li>大多数 push 是 O(1)</li><li>偶尔触发扩容,那一次是 O(n)(拷贝整个数组)</li><li>但扩容不是每次都发生——容量翻倍后,下次扩容要等 n/2 次 push</li><li>总共 push n 次,累计耗时 ≈ 2n,均摊 <strong>O(1)</strong></li></ul><p>均摊和平均的区别:<strong>均摊是对时间的平均,不管输入是什么</strong>;平均是对输入的平均。均摊更&quot;硬&quot;,因为它是<strong>确定性的上界</strong>。</p><h3 id="期望复杂度-expected" tabindex="-1">期望复杂度(Expected) <a class="header-anchor" href="#期望复杂度-expected" aria-label="Permalink to &quot;期望复杂度(Expected)&quot;">​</a></h3><p><strong>算法内部使用随机性时的期望值</strong>。随机化快排期望 O(n log n),最坏还是 O(n²),但因为基准是随机选的,<strong>构造出最坏情况的概率极低</strong>,所以工程上当 O(n log n) 用。</p><blockquote><p><strong>为什么哈希表是&quot;平均 O(1) 最坏 O(n)&quot; 不矛盾</strong>:哈希冲突严重时,链表退化,查找就变 O(n)。但在良好哈希函数 + 合理负载因子下,冲突概率极低,<strong>期望</strong>就是 O(1)。Java 8 的 HashMap 还做了一层保险:链表长度超过 8 自动转红黑树,<strong>把最坏从 O(n) 拉回 O(log n)</strong>。</p></blockquote><hr><h2 id="四、空间复杂度经常被忽视" tabindex="-1">四、空间复杂度经常被忽视 <a class="header-anchor" href="#四、空间复杂度经常被忽视" aria-label="Permalink to &quot;四、空间复杂度经常被忽视&quot;">​</a></h2><p>面试和业务里<strong>空间复杂度经常被忽略</strong>,但它能决定程序跑不跑得起来。</p><p>常见陷阱:</p><ul><li><strong>递归的隐形栈空间</strong>:一个看起来只占 O(1) 额外空间的递归,其实栈深度是 O(n),空间是 O(n)</li><li><strong>JS 里的 <code>arr.slice()</code></strong>:看起来写得优雅,<strong>每次都拷贝一遍</strong>,循环里滥用就 O(n²) 空间</li><li><strong>不必要的中间数组</strong>:<code>arr.map(...).filter(...).reduce(...)</code> 每步一个新数组,<strong>流式处理可以避免</strong></li></ul><p><strong>空间换时间 vs 时间换空间</strong>:两种思路在算法里反复出现。</p><ul><li>空间换时间:哈希表、DP 表、前缀和、缓存</li><li>时间换空间:流式处理、位运算、原地算法</li></ul><p>工程决策标准:<strong>内存贵的时候换时间,计算贵的时候换空间</strong>。现代服务器内存便宜,大多数时候是<strong>空间换时间</strong>。</p><hr><h2 id="五、递归的复杂度怎么算" tabindex="-1">五、递归的复杂度怎么算 <a class="header-anchor" href="#五、递归的复杂度怎么算" aria-label="Permalink to &quot;五、递归的复杂度怎么算&quot;">​</a></h2><p>递归算复杂度要考虑两件事:<strong>每层干多少活、总共多少层</strong>。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>T(n) = 子问题总时间 + 本层合并时间</span></span></code></pre></div><p>典型模式:</p><table tabindex="0"><thead><tr><th>递推式</th><th>复杂度</th><th>例子</th></tr></thead><tbody><tr><td>T(n) = T(n/2) + O(1)</td><td>O(log n)</td><td>二分</td></tr><tr><td>T(n) = T(n-1) + O(1)</td><td>O(n)</td><td>简单递归</td></tr><tr><td>T(n) = 2·T(n/2) + O(n)</td><td>O(n log n)</td><td>归并排序</td></tr><tr><td>T(n) = 2·T(n/2) + O(1)</td><td>O(n)</td><td>二叉树遍历</td></tr><tr><td>T(n) = T(n-1) + O(n)</td><td>O(n²)</td><td>选择排序式递归</td></tr><tr><td>T(n) = 2·T(n-1) + O(1)</td><td>O(2ⁿ)</td><td>不剪枝的枚举</td></tr></tbody></table><p><strong>不用背主定理</strong>,记住几个经典模式,剩下的靠类比就够用了。</p><hr><h2 id="六、工程视角的-真实复杂度" tabindex="-1">六、工程视角的&quot;真实复杂度&quot; <a class="header-anchor" href="#六、工程视角的-真实复杂度" aria-label="Permalink to &quot;六、工程视角的&quot;真实复杂度&quot;&quot;">​</a></h2><p>大 O 只是<strong>理论模型</strong>,工程上还有几个&quot;大 O 看不到&quot;的因素:</p><h3 id="_1-缓存命中率-常数差-10-倍" tabindex="-1">1. 缓存命中率(常数差 10 倍) <a class="header-anchor" href="#_1-缓存命中率-常数差-10-倍" aria-label="Permalink to &quot;1. 缓存命中率(常数差 10 倍)&quot;">​</a></h3><p>连续访问数组 vs 链表,理论都是 O(n),<strong>实际链表慢 5-10 倍</strong>——因为数组是连续内存,对 CPU 缓存极其友好;链表每跳一次都是 cache miss。</p><h3 id="_2-常数因子" tabindex="-1">2. 常数因子 <a class="header-anchor" href="#_2-常数因子" aria-label="Permalink to &quot;2. 常数因子&quot;">​</a></h3><p>两个 O(n log n) 算法,常数差 3 倍很常见。<strong>归并排序稳定但常数大,快排常数小是业界默认</strong>。</p><h3 id="_3-n-很小的时候" tabindex="-1">3. n 很小的时候 <a class="header-anchor" href="#_3-n-很小的时候" aria-label="Permalink to &quot;3. n 很小的时候&quot;">​</a></h3><p>O(n²) 在 n &lt; 50 可能比 O(n log n) 快,因为常数小、没递归调用开销。 <strong>标准库的排序(如 JDK 的 Arrays.sort)在小数组上切换成插入排序</strong>,就是这个原因。</p><h3 id="_4-分支预测-simd" tabindex="-1">4. 分支预测 / SIMD <a class="header-anchor" href="#_4-分支预测-simd" aria-label="Permalink to &quot;4. 分支预测 / SIMD&quot;">​</a></h3><p>现代 CPU 对<strong>有规律的循环</strong>做并行指令。算法写得对不对分支预测友好,能影响性能 2-3 倍。</p><blockquote><p><strong>结论</strong>:大 O 定方向(选 O(n log n) 还是 O(n²)),<strong>常数定细节</strong>(同级别里选哪种实现)。工程师两个都要看。</p></blockquote><hr><h2 id="七、快速估复杂度的套路" tabindex="-1">七、快速估复杂度的套路 <a class="header-anchor" href="#七、快速估复杂度的套路" aria-label="Permalink to &quot;七、快速估复杂度的套路&quot;">​</a></h2><p>给你一段代码,30 秒估出复杂度,套路:</p><ol><li><strong>看最深层循环</strong>,最深嵌套 k 层就是 O(n^k) 起步</li><li><strong>看循环里有没有 log 操作</strong>(二分 / 堆 / 平衡树),有就乘 log n</li><li><strong>看递归</strong>,T(n) 形式套上面的表</li><li><strong>看数据结构操作</strong>:HashMap 是 O(1)、TreeMap 是 O(log n)、排序是 O(n log n)</li></ol><p><strong>反过来估</strong>:你要做的事上限是 10⁶,那你必须控制在 O(n log n),有嵌套循环就危险;上限是 10⁴,O(n²) 还能活;上限是 20,O(2ⁿ) 都能玩。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>n ≤ 10       →  O(n!) 可以</span></span>
<span class="line"><span>n ≤ 25       →  O(2ⁿ) 可以</span></span>
<span class="line"><span>n ≤ 100      →  O(n⁴) 可以</span></span>
<span class="line"><span>n ≤ 500      →  O(n³) 可以</span></span>
<span class="line"><span>n ≤ 5000     →  O(n²) 可以</span></span>
<span class="line"><span>n ≤ 10⁶      →  O(n log n) 必须</span></span>
<span class="line"><span>n ≤ 10⁸      →  O(n) 必须</span></span>
<span class="line"><span>n &gt; 10⁸      →  O(log n) 或 O(1)</span></span></code></pre></div><p><strong>把这张表印在脑子里</strong>,面试看到数据范围就能倒推算法类别。</p><hr><h2 id="八、一句话总结" tabindex="-1">八、一句话总结 <a class="header-anchor" href="#八、一句话总结" aria-label="Permalink to &quot;八、一句话总结&quot;">​</a></h2><blockquote><p><strong>大 O 看增长趋势,均摊看操作序列,期望看随机性,最坏看你敢不敢上线</strong>。这四个词分清,你已经比 80% 的工程师懂复杂度了。</p></blockquote><p>下一篇讲递归与递推——为什么递归本质是&quot;栈&quot;、自顶向下和自底向上的切换怎么做、什么时候用递归什么时候必须改成迭代。</p>`,70)])])}const c=n(s,[["render",e]]);export{u as __pageData,c as default};
